import { useEffect, useMemo, useState } from 'react';
import './App.css';

const STORAGE_KEY = 'my-life-kanban-v1';

const COLUMNS = [
  { id: 'todo', title: 'To Do' },
  { id: 'doing', title: 'In Progress' },
  { id: 'review', title: 'Review' },
  { id: 'done', title: 'Done' },
];

const defaultTasks = [
  {
    id: crypto.randomUUID(),
    title: 'Define weekly top priorities',
    notes: 'Set 3 outcomes for the week.',
    owner: 'Both',
    status: 'todo',
    createdAt: Date.now(),
  },
  {
    id: crypto.randomUUID(),
    title: 'Build first board workflows',
    notes: 'Trading, Wellness Initiative, Family, Home projects.',
    owner: 'TheAIos',
    status: 'doing',
    createdAt: Date.now(),
  },
];

function App() {
  const [tasks, setTasks] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (!saved) return defaultTasks;
    try {
      return JSON.parse(saved);
    } catch {
      return defaultTasks;
    }
  });

  const [title, setTitle] = useState('');
  const [notes, setNotes] = useState('');
  const [owner, setOwner] = useState('Both');

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tasks));
  }, [tasks]);

  const counts = useMemo(() => {
    return COLUMNS.reduce((acc, col) => {
      acc[col.id] = tasks.filter((t) => t.status === col.id).length;
      return acc;
    }, {});
  }, [tasks]);

  const addTask = (e) => {
    e.preventDefault();
    if (!title.trim()) return;

    const newTask = {
      id: crypto.randomUUID(),
      title: title.trim(),
      notes: notes.trim(),
      owner,
      status: 'todo',
      createdAt: Date.now(),
    };

    setTasks((prev) => [newTask, ...prev]);
    setTitle('');
    setNotes('');
    setOwner('Both');
  };

  const moveTask = (taskId, newStatus) => {
    setTasks((prev) =>
      prev.map((task) =>
        task.id === taskId ? { ...task, status: newStatus } : task
      )
    );
  };

  const removeTask = (taskId) => {
    setTasks((prev) => prev.filter((task) => task.id !== taskId));
  };

  return (
    <div className="app-shell">
      <header className="topbar">
        <h1>My Life Board</h1>
        <p>Elegant, shared Kanban for Joseph + TheAIos</p>
      </header>

      <section className="composer-card">
        <form onSubmit={addTask} className="composer-form">
          <input
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="Add a task..."
            aria-label="Task title"
          />
          <input
            value={notes}
            onChange={(e) => setNotes(e.target.value)}
            placeholder="Optional details"
            aria-label="Task details"
          />
          <select value={owner} onChange={(e) => setOwner(e.target.value)}>
            <option>Both</option>
            <option>Joseph</option>
            <option>TheAIos</option>
          </select>
          <button type="submit">Add</button>
        </form>
      </section>

      <main className="board">
        {COLUMNS.map((column) => (
          <section
            key={column.id}
            className="column"
            onDragOver={(e) => e.preventDefault()}
            onDrop={(e) => {
              const taskId = e.dataTransfer.getData('text/plain');
              if (taskId) moveTask(taskId, column.id);
            }}
          >
            <div className="column-head">
              <h2>{column.title}</h2>
              <span>{counts[column.id] || 0}</span>
            </div>

            <div className="column-body">
              {tasks
                .filter((task) => task.status === column.id)
                .map((task) => (
                  <article
                    key={task.id}
                    className="task"
                    draggable
                    onDragStart={(e) =>
                      e.dataTransfer.setData('text/plain', task.id)
                    }
                  >
                    <div className="task-title">{task.title}</div>
                    {task.notes ? <p>{task.notes}</p> : null}
                    <div className="task-footer">
                      <span className="pill">{task.owner}</span>
                      <button onClick={() => removeTask(task.id)}>×</button>
                    </div>
                  </article>
                ))}
            </div>
          </section>
        ))}
      </main>
    </div>
  );
}

export default App;
